import type { ZeroAPISpec } from '../../types/spec.js'

export interface RenderOptions {
  buildCommand?: string
  startCommand?: string
  healthCheckPath?: string
  plan?: 'free' | 'starter' | 'standard' | 'pro'
  region?: string
}

/**
 * Generates a render.yaml service definition for deploying on Render.com.
 */
export function generateRenderConfig(
  spec: ZeroAPISpec,
  options: RenderOptions = {}
): string {
  const {
    buildCommand = 'npm install && npm run build',
    startCommand = 'node dist/index.js',
    healthCheckPath = '/health',
    plan = 'free',
    region = 'oregon',
  } = options

  const serviceName = spec.name.toLowerCase().replace(/[^a-z0-9-]/g, '-')

  return `# Generated by @ludagg/zeroapi-runtime for "${spec.name}" v${spec.version}
# Deploy: https://render.com

services:
  - type: web
    name: ${serviceName}
    runtime: node
    region: ${region}
    plan: ${plan}
    buildCommand: "${buildCommand}"
    startCommand: "${startCommand}"
    healthCheckPath: ${healthCheckPath}
    envVars:
      - key: NODE_ENV
        value: production
      - key: DATABASE_URL
        sync: false
`
}

/**
 * Returns a Markdown deploy-to-Render button for the given repository URL.
 */
export function getRenderDeployButton(repoUrl: string): string {
  const encoded = encodeURIComponent(repoUrl)
  return `[![Deploy to Render](https://render.com/images/deploy-to-render-button.svg)](https://render.com/deploy?repo=${encoded})`
}
